angular.module('myApp', [])
.directive('jsonDataGrid', function() {
    return {
        restrict: 'E',
        scope: {
            jsonData: '='
        },
        template: `
            <div>
                <table>
                    <thead>
                        <tr>
                            <th ng-repeat="header in headers">{{ header }}</th>
                        </tr>
                    </thead>
                    <tbody>
                        <tr ng-repeat="row in data">
                            <td ng-repeat="header in headers">{{ row[header] }}</td>
                        </tr>
                    </tbody>
                </table>
            </div>
        `,
        link: function(scope) {
            scope.$watch('jsonData', function(newValue) {
                if (newValue) {
                    try {
                        const parsedData = JSON.parse(newValue);
                        scope.headers = parsedData.settings.columns;
                        scope.data = parsedData.rows;
                    } catch (e) {
                        console.error('Invalid JSON data:', e);
                    }
                }
            });
        }
    };
});
